// ✅ Safe Notion Page Creation payload builder with TID support

const inputItems = $input.all();
const output = [];

// Helper: clean string
const getSafe = (val, fb = "") =>
  typeof val === "string" && val.trim() !== "" ? val.trim() : fb;

// Helper: parse to ISO (YYYY-MM-DD)
const toISODate = (val) => {
  if (!val) return null;
  if (/^\d{4}-\d{2}-\d{2}/.test(val)) return val;
  const parsed = new Date(val);
  if (isNaN(parsed.getTime())) return null;
  return parsed.toISOString().split("T")[0];
};

for (const item of inputItems) {
  const data = item.json;

  // Ensure Due Date is ISO or fallback to today
  const isoDate = toISODate(data["Due Date"]) || new Date().toISOString().split("T")[0];

  output.push({
    json: {
      parent: { database_id: "28b363499f1080f6817ad1ebaceebadc" },
      properties: {
        // ✅ New TID property
        TID: {
          rich_text: [
            { text: { content: getSafe(data.TID, "") } }
          ]
        },

        // Title
        Name: {
          title: [{ text: { content: getSafe(data.Title, "Untitled Task") } }]
        },

        // Workstream
        Workstream: {
          rich_text: [
            { text: { content: getSafe(data.Workstream, "General") } }
          ]
        },

        // Status
        Status: data.Status
          ? { select: { name: data.Status } }
          : { select: { name: "In Progress" } },

        // Due Date
        "Due Date": { date: { start: isoDate } },

        // Owner
        Owner: {
          rich_text: [
            { text: { content: getSafe(data.Owner, "MiniBox") } }
          ]
        },

        // Priority
        Priority: data.Priority
          ? { select: { name: data.Priority } }
          : { select: { name: "Medium" } },

        // Source
        Source: {
          rich_text: [
            { text: { content: getSafe(data.Source, "") } }
          ]
        },

        // Links
        Links: getSafe(data.Links)
          ? { url: getSafe(data.Links) }
          : { url: null },

        // Notes (optional)
        Notes: {
          rich_text: [
            { text: { content: getSafe(data.Notes, "") } }
          ]
        }
      }
    }
  });
}

return output;
